SELECT SUM(total_confirmed_cases) AS total_confirmed_cases
FROM lead_exposure
WHERE year = 2020;

SELECT SUM(total_confirmed_cases) AS total_cases_2016
FROM lead_exposure
WHERE year = 2016;

SELECT year, total_confirmed_cases
FROM lead_exposure
WHERE total_confirmed_cases = (
    SELECT MAX(total_confirmed_cases)
    FROM lead_exposure
);

SELECT SUM(total_population) AS total_population_sum
FROM population
WHERE subregion_id = 0;

SELECT AVG(percent_tested) AS average_percentage_tested
FROM lead_exposure
WHERE year = 2020;

SELECT AVG(population_density) AS average_population_density
FROM subregions
WHERE average_income > 40000;

SELECT subregion_id, SUM(total_confirmed_cases) AS total_confirmed_cases_sum
FROM lead_exposure
GROUP BY subregion_id;
